/**
 * Typed error returned across the FFI boundary.
 * Swift receives a `FfiError` enum that can be pattern-matched in do/catch.
 */
public enum FfiError {

    
    
    case Db(msg: String
    )
    case NotFound(msg: String
    )
    case InvalidArgument(msg: String
    )
    case AlreadyFinalized
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeFfiError: FfiConverterRustBuffer {
    typealias SwiftType = FfiError

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> FfiError {
        let variant: Int32 = try readInt(&buf)
        switch variant {

        

        
        case 1: return .Db(
            msg: try FfiConverterString.read(from: &buf)
            )
        case 2: return .NotFound(
            msg: try FfiConverterString.read(from: &buf)
            )
        case 3: return .InvalidArgument(
            msg: try FfiConverterString.read(from: &buf)
            )
        case 4: return .AlreadyFinalized

         default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: FfiError, into buf: inout [UInt8]) {
        switch value {

        

        
        
        case let .Db(msg):
            writeInt(&buf, Int32(1))
